  ('judicial-57f41407-moex-00733', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於阻卻違法事由之敘述，何者錯誤？', '["阻卻違法事由包括法規阻卻違法事由及超法規阻卻違法事由", "阻卻違法事由等同於阻卻罪責事由", "在三階層理論下，行為人之行為具有構成要件該當性，未必當然即具有違法性", "在三階層理論下，行為人之行為具有構成要件該當性、違法性，未必當然即具有罪責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00734', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '八大行業業者甲為求提早得知臨檢訊息，與員警乙約定由乙提早提供訊息，甲則按月交付乙新臺幣5萬元 現金作為酬勞，乙並與知情的配偶丙商量，由丙前往約定地點收取，以躲避查緝。丙所為應如何處斷？', '["違背職務行賄罪之幫助犯", "違背職務收受賄賂罪之共同正犯", "違背職務行賄罪之共同正犯", "丙非公務員，故不成罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00735', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於刑法第23條「現在不法之侵害」，下列敘述何者錯誤？', '["侵害必須來自於人為之不法行為", "侵害善良風俗亦可主張正當防衛", "對合法行為不能為正當防衛", "侵害行為包括作為及不作為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00736', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '刑法第135條第3項規定，關於公務員依法執行職務時，施強暴脅迫者加重其刑之規定，下列敘述何者錯誤？', '["以駕駛動力交通工具犯之者，有加重其刑規定之適用", "意圖供行使之用而攜帶兇器犯之者，有加重其刑規定之適用", "僅單純駕駛動力交通工具到場，即有加重其刑規定之適用", "意圖供行使之用而攜帶危險物品犯之者，有加重其刑規定之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00737', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲公務員對於其主管之事務，明知違背法令，卻因收受民眾乙交付新臺幣 20 萬元現金，而違背其職務直 接圖謀乙之不法利益，並使乙獲得該不法利益，則甲構成貪污治罪條例之何項罪名？', '["只成立對於主管事務圖利罪", "對於違背職務行為要求賄賂罪", "對於違背職務行為收受賄賂罪", "同時構成對於主管事務圖利罪及對於違背職務行為收受賄賂罪，二罪併罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00738', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依家庭暴力防治法在使用於公權力介入家庭暴力事件時，根據該法所謂的「家庭暴力」，乃是家庭成員間 實施身體或精神上不法侵害之行為。下列那些事件，不符合該法中所謂的家庭暴力事件？', '["離婚後的前夫破門毆打原岳父", "夜夜磨刀的孫子詛咒爺爺去死", "同居之三等旁系血親的互毆", "曾經同居的分手情侶欠錢不還糾紛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00739', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '國家基於肯定多元文化的價值，積極保障各族群的權益，下列何者不是我國目前對原住民族所採行的措施？', '["將山胞正名為原住民，且2010年起各族可依「歲時祭儀」需要放假一日", "通過《姓名條例》修正案，原住民名字可在中文譯音旁加註羅馬拼音", "成立原住民自治區，原住民得以在自治區內施行原住民族自治法", "辦理原住民學生語言及文化能力證明，取得升學優待提升學習競爭力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00740', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '國外源起「待用咖啡」的原型，是由消費者預付款項給店家，待需要的弱勢者取用。而國內衍伸「待用餐 食」的模式，不僅店家主動加入，甚至自行吸收食材的成本，下列敘述何者正確？', '["該做法發想與活動促進者皆屬非營利組織", "凸顯不同文化資本中搭便車行為的普遍性", "制度順利運行必須根植於社會資本的累積", "企業才能是此一模式發想推展的關鍵要素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00741', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '美國哈佛大學邀請脫口秀天后歐普拉（Oprah Winfrey）為2013年畢業生演講，歐普拉出生在典型的黑人 貧戶家庭，生父不詳。大學尚未畢業，她就利用善於說話的天賦本能，成為地方電視台的首位黑人女主播， 隨後並創辦「脫口秀節目」，成為全美收視率最高的電視主持人，更被譽為美國最有權勢和影響力的人。 關於歐普拉的社會流動，下列敘述何者錯誤？', '["水平流動", "垂直流動", "代內流動", "結構流動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00742', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '新聞報導：某市政府與超商業者合作，針對就讀、設籍於該市或在該市內發生「急難事由」致有飢餓求助 需求學童，提供每人每餐80元供餐協助，採「救急不救窮」為原則。關於此一作法，下列敘述何者正確？', '["屬政府與第二部門合作的公私協力模式", "有助文化資本的累續，公民社會的形成", "屬於藉由民間募款支應的短期社會津貼", "企業善盡社會責任，展現組織運作自主"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
